async def execute_tool(agent_key: str, tool_name: str, tool_input: str) -> str:
    """Execute a tool dynamically and return text findings."""
    logger.info(f"Agent '{agent_key}' invoking tool '{tool_name}' with input: '{tool_input}'")
    
    # Introduce a short delay to simulate network latency
    await asyncio.sleep(0.5)
    
    input_lower = tool_input.lower()
    
    # Identify which keyword domain we are in
    domain = "software"
    if "agent" in input_lower or "langgraph" in input_lower or "multi-agent" in input_lower:
        domain = "agentic"
    elif "health" in input_lower or "clinic" in input_lower or "patient" in input_lower or "doctor" in input_lower:
        domain = "health"
    elif "vehicle" in input_lower or "autonomous" in input_lower or "car" in input_lower or "driver" in input_lower:
        domain = "vehicle"
    elif "climate" in input_lower or "carbon" in input_lower or "temperature" in input_lower or "greenhouse" in input_lower:
        domain = "climate"
    elif "security" in input_lower or "phish" in input_lower or "malware" in input_lower or "zero-day" in input_lower:
        domain = "cybersecurity"

    data = KNOWLEDGE_BASE[domain]

    # Tool execution routing
    if tool_name in ["web_search", "web_search_cross"]:
        return f"[Web Search Results for '{tool_input}'] - {data['web']}"
        
    elif tool_name == "url_reader":
        return f"[URL Content Extracted from '{tool_input}'] - Parsed page details confirm: {data['web'][:120]} ... Verified by secure enterprise proxy."
        
    elif tool_name == "wikipedia_search":
        return f"[Wikipedia Summary for '{tool_input}'] - {data['wiki']}"
        
    elif tool_name == "arxiv_search":
        return f"[ArXiv Paper Reference for '{tool_input}'] - {data['arxiv']}"
        
    elif tool_name == "logic_checker":
        return f"[Logical Consistency Check] - Scanned findings. Result: Logic is structurally sound. Logical induction checks passed with 94% alignment. Note: critique checks for correlation vs. causation."
        
    elif tool_name == "bias_detector":
        return f"[Bias Scan] - Analyzed stance text. Result: Mild selection bias flagged in early adopters. Vendor-sponsored studies have high optimism bias. Neutralizing instructions applied."
        
    elif tool_name == "contradiction_analyzer":
        return f"[Contradiction Scan] - Scanned inputs. Result: No direct logical contradictions found. Minor semantic conflicts regarding developer role evolution resolved."
        
    elif tool_name in ["news_search", "market_trend_search", "tech_trend_search"]:
        return f"[Trend Analysis Search for '{tool_input}'] - {data['trend']}"
        
    elif tool_name == "source_verifier":
        return f"[Source Verifier for '{tool_input}'] - Source status: TRUSTED. Indexed in academic databases. Peer-review status: Confirmed."
        
    elif tool_name == "contradiction_detector":
        return f"[Contradiction Check] - Consistency verified. Stance on '{tool_input}' matches findings with standard deviations < 5%."
        
    else:
        return f"[Tool '{tool_name}' output] - No matching records found. Standard mock feedback returned for input: '{tool_input}'"
